UPDATE ${schema}.user_menu_authrt
SET
inq_authrt_yn = CASE


        WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
        THEN #{auth.inqAuthrtYn}


ELSE inq_authrt_yn
END,
wrt_authrt_yn = CASE


        WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
        THEN #{auth.wrtAuthrtYn}


ELSE wrt_authrt_yn
END,
del_authrt_yn = CASE


        WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
        THEN #{auth.delAuthrtYn}


ELSE del_authrt_yn
END,
excel_authrt_yn = CASE


        WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
        THEN #{auth.excelAuthrtYn}


ELSE excel_authrt_yn
END,
otpt_authrt_yn = CASE


        WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
        THEN #{auth.otptAuthrtYn}


ELSE otpt_authrt_yn
END,
use_yn = CASE


        WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
        THEN #{auth.useYn}


ELSE use_yn
END,


        auth_bgng_dt = CASE

            WHEN user_oid = #{innerAuth.userOid} AND menu_oid = #{innerAuth.menuOid} AND user_menu_authrt_oid = #{innerAuth.userMenuAuthrtOid}
            THEN #{innerAuth.authBgngDt}

        ELSE auth_bgng_dt
        END,




        auth_end_dt = CASE

            WHEN user_oid = #{innerAuth.userOid} AND menu_oid = #{innerAuth.menuOid} AND user_menu_authrt_oid = #{innerAuth.userMenuAuthrtOid}
            THEN #{innerAuth.authEndDt}

        ELSE auth_end_dt
        END,


mdfcn_id = CASE

    WHEN user_oid = #{auth.userOid} AND menu_oid = #{auth.menuOid} AND user_menu_authrt_oid = #{auth.userMenuAuthrtOid}
    THEN #{auth.mdfcnId}

ELSE mdfcn_id
END,
mdfcn_dt = NOW()
WHERE user_menu_authrt_oid IN

    #{auth.userMenuAuthrtOid}

UPDATE
    ${schema}.user
SET
    prvc_use_yn = #{prvcUseYn}
  , mdfcn_id = #{mdfcnId}
  , mdfcn_dt = NOW()
WHERE user_oid = #{userOid}

mapper.insert:
INSERT INTO ${schema}.user_menu_authrt ( user_oid, menu_oid, inq_authrt_yn, wrt_authrt_yn, del_authrt_yn, excel_authrt_yn, otpt_authrt_yn, use_yn, auth_bgng_dt, auth_end_dt, reg_id, reg_dt, mdfcn_id, mdfcn_dt ) SELECT target.user_oid, source.menu_oid, source.inq_authrt_yn, source.wrt_authrt_yn, source.del_authrt_yn, source.excel_authrt_yn, source.otpt_authrt_yn, source.use_yn, CURDATE(), DATE_ADD(CURDATE(), INTERVAL 2 YEAR), #{regId}, NOW(), #{regId}, NOW() FROM ${schema}.user_menu_authrt source CROSS JOIN (
SELECT #{userOid} AS user_oid
) target WHERE source.user_oid = #{sourceUserNo} AND source.use_yn = 'Y'
